const checkpoints = [];

const services = JSON.parse(localStorage.getItem('services') || '[]');
const slots = JSON.parse(localStorage.getItem('availability_slots') || '[]');
const bookings = JSON.parse(localStorage.getItem('bookings') || '[]');

// Helper: does a slot meet the time/price/service criteria (but NOT tied to a specific booking)?
function slotMeetsCriteria(slot) {
  if (!slot || !slot.start_datetime) return false;
  const service = services.find(s => s.id === slot.service_id);
  if (!service || service.category_id !== 'home_office') return false;
  if (slot.location_type !== 'in_home') return false;
  if (slot.duration_minutes !== 120) return false;
  const price = Number(slot.price_total || 0);
  if (price > 200) return false;
  const start = new Date(slot.start_datetime);
  if (isNaN(start.getTime())) return false;
  const year = start.getUTCFullYear();
  const month = start.getUTCMonth(); // 0-based, 8 = September
  const day = start.getUTCDate();
  // Mid-September 2026: loosely treat as days 10–20 of September 2026
  if (year !== 2026 || month !== 8 || day < 10 || day > 20) return false;
  const hour = start.getUTCHours();
  // Afternoon window 2–5 pm (14:00–17:59 start)
  if (hour < 14 || hour > 17) return false;
  return true;
}

// All candidate slots that could satisfy the task
const candidateSlots = slots.filter(slotMeetsCriteria);

// Find bookings that meet all requirements EXCEPT the "cheapest" constraint
const qualifyingBookings = bookings.filter(b => {
  if (!b || !b.availability_slot_id) return false;
  if (b.customer_name !== 'Alex Rivera') return false;
  if (b.customer_email !== 'alex.rivera@example.com') return false;
  if (b.customer_phone !== '555-123-7890') return false;
  if (b.payment_option !== 'pay_at_appointment') return false;

  const slot = slots.find(s => s.id === b.availability_slot_id);
  if (!slotMeetsCriteria(slot)) return false;

  return true;
});

// Determine the cheapest candidate slot under all constraints (regardless of booking)
let cheapestSlot = null;
if (candidateSlots.length > 0) {
  cheapestSlot = candidateSlots.reduce((min, s) => {
    if (!min) return s;
    const pMin = Number(min.price_total || 0);
    const pS = Number(s.price_total || 0);
    return pS < pMin ? s : min;
  }, null);
}

// Checkpoint 1 (0.6): User created at least one booking for Alex Rivera that meets
// all time/location/service/price criteria with pay-at-appointment.
checkpoints.push({
  passed: qualifyingBookings.length > 0,
  weight: 0.6
});

// Checkpoint 2 (0.4): Among all qualifying slots, the booked one is the cheapest.
const bookedCheapest = !!(cheapestSlot && qualifyingBookings.some(b => {
  const slot = slots.find(s => s.id === b.availability_slot_id);
  return slot && slot.id === cheapestSlot.id;
}));

checkpoints.push({
  passed: bookedCheapest,
  weight: 0.4
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const packages = JSON.parse(localStorage.getItem('packages') || '[]');
const addons = JSON.parse(localStorage.getItem('addon_services') || '[]');
const packageConfigurations = JSON.parse(localStorage.getItem('package_configurations') || '[]');
const cart = JSON.parse(localStorage.getItem('cart') || 'null');
const cartItems = JSON.parse(localStorage.getItem('cart_items') || '[]');

// Identify whole-home packages
const wholeHomePackageIds = packages
  .filter(p => p && p.category_id === 'whole_home')
  .map(p => p.id);

// Find cart items that are package items for whole-home packages
const wholeHomeCartItems = (cart && Array.isArray(cart.items) ? cart.items : [])
  .map(id => cartItems.find(ci => ci && ci.id === id))
  .filter(ci => ci && ci.item_type === 'package' && wholeHomePackageIds.includes(ci.package_id));

// For each such cart item, verify its configuration meets the bedroom/add-on constraints
let hasValidConfiguredPackage = false;
for (const ci of wholeHomeCartItems) {
  const cfg = packageConfigurations.find(pc => pc && pc.id === ci.package_configuration_id);
  if (!cfg) continue;

  if (cfg.bedrooms !== 3) continue;
  const selectedIds = Array.isArray(cfg.selected_addon_ids) ? cfg.selected_addon_ids : [];
  if (selectedIds.length !== 2) continue;

  const selectedAddons = addons.filter(a => a && selectedIds.includes(a.id));
  if (selectedAddons.length !== 2) continue;

  const prices = selectedAddons.map(a => Number(a.price || 0));
  if (prices.some(p => p >= 50)) continue;
  const sum = prices.reduce((s, p) => s + p, 0);
  if (sum >= 80) continue;

  hasValidConfiguredPackage = true;
  break;
}

// Single checkpoint (1.0): At least one package in the cart is a whole-home package
// configured for 3 bedrooms with exactly two add-ons, each under $50 and combined under $80.
checkpoints.push({
  passed: hasValidConfiguredPackage,
  weight: 1.0
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const products = JSON.parse(localStorage.getItem('products') || '[]');
const cart = JSON.parse(localStorage.getItem('cart') || 'null');
const cartItems = JSON.parse(localStorage.getItem('cart_items') || '[]');

// Find qualifying products in Closet & Wardrobe Storage that match all criteria
const qualifyingProducts = products.filter(p => {
  if (!p || p.status !== 'active') return false;
  if (p.category_id !== 'closet_wardrobe_storage') return false;
  const price = Number(p.price || 0);
  if (price < 15 || price > 30) return false;
  if (typeof p.capacity_liters !== 'number' || p.capacity_liters < 20) return false;
  if (!p.free_shipping) return false;
  if (!p.color || String(p.color).toLowerCase() !== 'clear') return false;
  const rating = Number(p.average_rating || 0);
  if (rating < 4) return false;
  return true;
});

const qualifyingIds = qualifyingProducts.map(p => p.id);

// Look for a cart item with quantity exactly 4 for one qualifying product
let hasFourQualifyingBins = false;
if (cart && Array.isArray(cart.items)) {
  for (const id of cart.items) {
    const ci = cartItems.find(x => x && x.id === id);
    if (!ci || ci.item_type !== 'product') continue;
    if (!qualifyingIds.includes(ci.product_id)) continue;
    if (Number(ci.quantity || 0) === 4) {
      hasFourQualifyingBins = true;
      break;
    }
  }
}

// Single checkpoint (1.0): Cart contains a line with quantity 4 of a qualifying clear bin product.
checkpoints.push({
  passed: hasFourQualifyingBins,
  weight: 1.0
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const packages = JSON.parse(localStorage.getItem('packages') || '[]');
const promoCodes = JSON.parse(localStorage.getItem('promo_codes') || '[]');
const orders = JSON.parse(localStorage.getItem('orders') || '[]');
const orderItems = JSON.parse(localStorage.getItem('order_items') || '[]');

// Determine the cheapest virtual coaching bundle with 3 sessions of 60 minutes
const candidateBundles = packages.filter(p => {
  if (!p) return false;
  if (p.category_id !== 'virtual_decluttering_coaching') return false;
  if (typeof p.session_count !== 'number' || p.session_count !== 3) return false;
  if (typeof p.session_length_minutes !== 'number' || p.session_length_minutes !== 60) return false;
  return p.status === 'active';
});

let cheapestBundle = null;
if (candidateBundles.length > 0) {
  cheapestBundle = candidateBundles.reduce((min, p) => {
    if (!min) return p;
    const priceMin = Number(min.base_price || 0);
    const priceP = Number(p.base_price || 0);
    return priceP < priceMin ? p : min;
  }, null);
}

// Find orders created with Jordan Kim's contact details
const jordanOrders = orders.filter(o => o && o.contact_name === 'Jordan Kim' && o.contact_email === 'jordan.kim@example.com');

// Among those, find one that contains the cheapest qualifying bundle as a package item
let targetOrder = null;
if (cheapestBundle && jordanOrders.length > 0) {
  for (const o of jordanOrders) {
    const items = (o.items || []).map(id => orderItems.find(oi => oi && oi.id === id)).filter(Boolean);
    const hasBundle = items.some(oi => oi.item_type === 'package' && oi.reference_id === cheapestBundle.id);
    if (hasBundle) {
      targetOrder = o;
      break;
    }
  }
}

// Locate the TIDY10 promo code
const tidyPromo = promoCodes.find(p => p && String(p.code || '').toUpperCase() === 'TIDY10' && p.is_active);
let tidyIsCurrentlyValid = false;
if (tidyPromo) {
  const now = new Date();
  let within = true;
  if (tidyPromo.valid_from) {
    within = within && now >= new Date(tidyPromo.valid_from);
  }
  if (tidyPromo.valid_to) {
    within = within && now <= new Date(tidyPromo.valid_to);
  }
  tidyIsCurrentlyValid = within;
}

// Checkpoint 1 (0.4): Jordan's order exists and includes the cheapest qualifying 3×60 virtual bundle.
checkpoints.push({
  passed: !!targetOrder,
  weight: 0.4
});

// Checkpoint 2 (0.3): That order used the TIDY10 promo code, which is an active 10% code.
const usedTidy10 = !!(targetOrder && tidyPromo && tidyIsCurrentlyValid && targetOrder.promo_code && String(targetOrder.promo_code).toUpperCase() === 'TIDY10' && tidyPromo.discount_type === 'percentage' && Number(tidyPromo.discount_value || 0) === 10);
checkpoints.push({
  passed: usedTidy10,
  weight: 0.3
});

// Checkpoint 3 (0.3): The promo actually produced a discount on the order total.
const discountApplied = !!(targetOrder && Number(targetOrder.discount_total || 0) > 0);
checkpoints.push({
  passed: discountApplied,
  weight: 0.3
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const requests = JSON.parse(localStorage.getItem('assessment_requests') || '[]');

const matchingRequest = requests.find(r => {
  if (!r) return false;
  if (r.name !== 'Taylor Morgan') return false;
  if (r.email !== 'taylor.morgan@example.com') return false;
  // Home details
  if (r.home_type !== 'apartment') return false;
  if (typeof r.bedrooms !== 'number' || r.bedrooms !== 2) return false;
  if (typeof r.square_footage !== 'number' || r.square_footage !== 900) return false;
  // Preferred day/time
  if (r.preferred_day !== 'wednesday') return false;
  if (r.preferred_time_window !== 'evening_5_8') return false;
  // Budget note text and numeric budget
  const notes = String(r.notes || '').toLowerCase();
  if (!notes.includes('budget') || !notes.includes('400')) return false;
  if (typeof r.budget_amount !== 'number' || !(r.budget_amount <= 400)) return false;
  return true;
});

// Single checkpoint (1.0): Such a fully matching assessment request exists.
checkpoints.push({
  passed: !!matchingRequest,
  weight: 1.0
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const articles = JSON.parse(localStorage.getItem('articles') || '[]');
const readingListItems = JSON.parse(localStorage.getItem('reading_list_items') || '[]');
const downloads = JSON.parse(localStorage.getItem('downloads') || '[]');
const cart = JSON.parse(localStorage.getItem('cart') || 'null');
const cartItems = JSON.parse(localStorage.getItem('cart_items') || '[]');

// Threshold for "within the last 6 months" based on ground truth (2025-09-03)
const thresholdDate = new Date('2025-09-03T00:00:00Z');

// 1. Find saved articles that match: Kitchen Organization + Small Kitchens tag + recent
const savedArticleIds = readingListItems.map(r => r.article_id);

const qualifyingSavedArticles = articles.filter(a => {
  if (!a) return false;
  if (!savedArticleIds.includes(a.id)) return false;
  if (a.category_id !== 'kitchen_organization') return false;
  if (!Array.isArray(a.tag_ids) || !a.tag_ids.includes('small_kitchens')) return false;
  const pub = new Date(a.published_at);
  if (isNaN(pub.getTime()) || pub < thresholdDate) return false;
  return true;
});

const qualifyingArticleIds = qualifyingSavedArticles.map(a => a.id);

// 2. Among cart items, find free checklist downloads that are related to at least one qualifying article
let hasRelatedFreeChecklistInCart = false;
if (cart && Array.isArray(cart.items)) {
  for (const id of cart.items) {
    const ci = cartItems.find(x => x && x.id === id);
    if (!ci || ci.item_type !== 'download') continue;
    const dl = downloads.find(d => d && d.id === ci.download_id);
    if (!dl) continue;
    if (dl.type !== 'checklist' || !dl.is_free) continue;
    const relatedIds = Array.isArray(dl.related_article_ids) ? dl.related_article_ids : [];
    const overlaps = relatedIds.some(aid => qualifyingArticleIds.includes(aid));
    if (overlaps) {
      hasRelatedFreeChecklistInCart = true;
      break;
    }
  }
}

// Checkpoint 1 (0.4): At least one qualifying recent small-kitchen article is saved.
checkpoints.push({
  passed: qualifyingSavedArticles.length > 0,
  weight: 0.4
});

// Checkpoint 2 (0.6): A free checklist download related to one of those articles is in the cart.
checkpoints.push({
  passed: hasRelatedFreeChecklistInCart,
  weight: 0.6
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const giftProducts = JSON.parse(localStorage.getItem('gift_card_products') || '[]');
const giftDesigns = JSON.parse(localStorage.getItem('gift_card_designs') || '[]');
const giftConfigs = JSON.parse(localStorage.getItem('gift_card_configurations') || '[]');
const shippingMethods = JSON.parse(localStorage.getItem('shipping_methods') || '[]');
const cart = JSON.parse(localStorage.getItem('cart') || 'null');
const cartItems = JSON.parse(localStorage.getItem('cart_items') || '[]');
const orders = JSON.parse(localStorage.getItem('orders') || '[]');
const orderItems = JSON.parse(localStorage.getItem('order_items') || '[]');

// 1. Find a gift card configuration that matches the physical $150 card and neutral design and names/occasion
let matchingConfig = null;
for (const cfg of giftConfigs) {
  if (!cfg) continue;
  const product = giftProducts.find(p => p && p.id === cfg.gift_card_product_id && p.is_active);
  if (!product || product.type !== 'physical') continue;
  const amount = Number(cfg.amount || 0);
  if (amount !== 150) continue;
  // Check min/max bounds just to ensure it's within allowed range
  if (typeof product.min_amount === 'number' && amount < product.min_amount) continue;
  if (typeof product.max_amount === 'number' && amount > product.max_amount) continue;

  const design = cfg.design_id ? giftDesigns.find(d => d && d.id === cfg.design_id) : null;
  if (!design || !design.is_neutral) continue; // neutral, non-seasonal

  if (cfg.occasion !== 'birthday') continue;
  if (cfg.recipient_name !== 'Sam Lee') continue;
  if (cfg.sender_name !== 'Pat Jordan') continue;

  matchingConfig = cfg;
  break;
}

// 2. Check that there is a cart item for this config with Standard Shipping under $8
let hasStandardShipping = false;
if (matchingConfig && cart && Array.isArray(cart.items)) {
  for (const id of cart.items) {
    const ci = cartItems.find(x => x && x.id === id);
    if (!ci || ci.item_type !== 'gift_card') continue;
    if (ci.gift_card_configuration_id !== matchingConfig.id) continue;
    const sm = shippingMethods.find(sm => sm && sm.id === ci.shipping_method_id);
    if (!sm) continue;
    if (sm.code === 'standard' && Number(sm.price || 0) < 8) {
      hasStandardShipping = true;
      break;
    }
  }
}

// 3. Verify an order exists that includes this gift card configuration (i.e., checkout started)
let orderIncludesConfig = false;
if (matchingConfig) {
  for (const o of orders) {
    if (!o || !Array.isArray(o.items)) continue;
    const items = o.items.map(id => orderItems.find(oi => oi && oi.id === id)).filter(Boolean);
    const hasCfg = items.some(oi => oi.item_type === 'gift_card' && oi.reference_id === matchingConfig.id);
    if (hasCfg) {
      orderIncludesConfig = true;
      break;
    }
  }
}

// Checkpoint 1 (0.4): A matching physical $150 neutral-design birthday gift card configuration for Sam Lee/Pat Jordan exists.
checkpoints.push({
  passed: !!matchingConfig,
  weight: 0.4
});

// Checkpoint 2 (0.3): That configuration is in the cart with Standard Shipping under $8.
checkpoints.push({
  passed: !!matchingConfig && hasStandardShipping,
  weight: 0.3
});

// Checkpoint 3 (0.3): An order exists that includes this gift card configuration (user reached checkout).
checkpoints.push({
  passed: !!matchingConfig && orderIncludesConfig,
  weight: 0.3
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const packages = JSON.parse(localStorage.getItem('packages') || '[]');
const slots = JSON.parse(localStorage.getItem('availability_slots') || '[]');
const bookings = JSON.parse(localStorage.getItem('bookings') || '[]');

// 1. Determine the eligible closet packages (≥10 hours, price < 600) and pick highest rated
const eligiblePackages = packages.filter(p => {
  if (!p) return false;
  if (p.category_id !== 'closet_wardrobe_organization') return false;
  if (typeof p.total_hours !== 'number' || p.total_hours < 10) return false;
  if (Number(p.base_price || 0) > 600) return false;
  return p.status === 'active';
});

let bestPackage = null;
if (eligiblePackages.length > 0) {
  bestPackage = eligiblePackages.reduce((best, p) => {
    if (!best) return p;
    const rBest = Number(best.average_rating || 0);
    const rP = Number(p.average_rating || 0);
    if (rP > rBest) return p;
    if (rP < rBest) return best;
    // tie-breaker: cheaper first
    const priceBest = Number(best.base_price || 0);
    const priceP = Number(p.base_price || 0);
    return priceP < priceBest ? p : best;
  }, null);
}

// 2. Define next-month Saturday morning criteria based on ground truth (April 2026)
// Ground truth uses 2026-04 as the next month, so constrain to April 2026 Saturdays 9:00–13:00.
function slotMeetsTimeWindow(slot) {
  if (!slot || !slot.start_datetime) return false;
  const start = new Date(slot.start_datetime);
  if (isNaN(start.getTime())) return false;
  const year = start.getUTCFullYear();
  const month = start.getUTCMonth(); // 0-based, 3 = April
  if (year !== 2026 || month !== 3) return false;
  const dayOfWeek = start.getUTCDay(); // 6 = Saturday
  if (dayOfWeek !== 6) return false;
  const hour = start.getUTCHours();
  if (hour < 9 || hour >= 13) return false;
  return true;
}

// 3. Find bookings that are for the bestPackage and within the required time window
const qualifyingBookings = bookings.filter(b => {
  if (!b || !bestPackage) return false;
  if (b.package_id !== bestPackage.id) return false;
  const slot = slots.find(s => s && s.id === b.availability_slot_id);
  if (!slotMeetsTimeWindow(slot)) return false;
  if (slot.location_type !== 'in_home') return false;
  return true;
});

// Single checkpoint (1.0): At least one booking exists for the highest-rated eligible package in the correct Saturday morning window.
checkpoints.push({
  passed: qualifyingBookings.length > 0,
  weight: 1.0
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);
